Pseudo-code:
```python
from celery import Celery
from datetime import datetime, timedelta
import yfinance as yf
from typing import List, Dict

app = Celery('market_monitor')

class MarketMonitor:
    def __init__(self):
        self.yahoo = yf.Ticker
        self.news_api = NewsAPIClient()

    def check_price_movement(self, ticker: str, threshold: float) -> Dict:
        stock = self.yahoo(ticker)
        current = stock.info.get('currentPrice', 0)
        previous = stock.info.get('previousClose', 0)

        if previous > 0:
            change_pct = ((current - previous) / previous) * 100
            if abs(change_pct) >= threshold:
                return {
                    'triggered': True,
                    'ticker': ticker,
                    'current_price': current,
                    'previous_close': previous,
                    'change_pct': change_pct,
                    'timestamp': datetime.now()
                }
        return {'triggered': False}

    def check_news_events(self, ticker: str, keywords: List[str]) -> List[Dict]:
        # Search for news with relevance scoring
        news = self.news_api.search(
            query=f'{ticker} {" OR ".join(keywords)}',
            from_date=(datetime.now() - timedelta(hours=24)),
            language='en,ar'
        )

        significant_news = []
        for article in news:
            relevance = self._calculate_relevance(article, ticker, keywords)
            if relevance > 0.7:
                significant_news.append({
                    'title': article['title'],
                    'url': article['url'],
                    'published': article['publishedAt'],
                    'relevance': relevance,
                    'summary': article['description']
                })
        return significant_news

@app.task
def monitor_watchlists():
    """Celery task to run every 15 minutes during market hours"""
    monitor = MarketMonitor()

    # Get all active watchlist items with alerts
    items = db.query(WatchlistItem).join(WatchlistAlert).filter(
        WatchlistAlert.is_active == True
    ).all()

    for item in items:
        # Check each alert condition
        for alert in item.alerts:
            if alert.alert_type == 'price_change':
                result = monitor.check_price_movement(
                    item.ticker, 
                    alert.threshold_value
                )
                if result['triggered']:
                    create_notification(item.user_id, alert, result)

            elif alert.alert_type == 'news_event':
                news = monitor.check_news_events(
                    item.ticker,
                    alert.keywords or ['earnings', 'merger', 'acquisition']
                )
                if news:
                    create_notification(item.user_id, alert, {'news': news})

# Schedule task
app.conf.beat_schedule = {
    'monitor-watchlists': {
        'task': 'monitor_watchlists',
        'schedule': crontab(minute='*/15', hour='6-16'),  # Saudi market hours
    },
}
```

