// components/ReportHistory.tsx
import { useState, useEffect } from 'react';
import { Timeline, TimelineItem } from '@/components/ui/timeline';
import { formatDistanceToNow } from 'date-fns';
import { ar, enUS } from 'date-fns/locale';

interface ReportVersion {
  id: number;
  version_number: number;
  created_at: string;
  created_by: { name: string; avatar?: string };
  change_summary: string;
  metrics_summary: {
    revenue_change: number;
    earnings_change: number;
    rating_change?: string;
  };
}

export function ReportHistory({ ticker }: { ticker: string }) {
  const [versions, setVersions] = useState<ReportVersion[]>([]);
  const [selectedVersions, setSelectedVersions] = useState<[number?, number?]>([]);
  const { locale } = useLocale();

  useEffect(() => {
    fetchReportVersions(ticker).then(setVersions);
  }, [ticker]);

  const handleCompare = () => {
    if (selectedVersions[0] && selectedVersions[1]) {
      router.push(`/reports/compare?v1=${selectedVersions[0]}&v2=${selectedVersions[1]}`);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold">
          {locale === 'ar' ? 'تاريخ التقارير' : 'Report History'}
        </h2>
        <button
          onClick={handleCompare}
          disabled={selectedVersions.filter(Boolean).length !== 2}
          className="btn-primary"
        >
          {locale === 'ar' ? 'مقارنة النسخ' : 'Compare Versions'}
        </button>
      </div>

      <Timeline>
        {versions.map((version) => (
          <TimelineItem
            key={version.id}
            active={selectedVersions.includes(version.id)}
            onClick={() => toggleVersionSelection(version.id)}
          >
            <div className="flex items-start justify-between">
              <div>
                <h3 className="font-semibold">
                  {locale === 'ar' ? `النسخة ${version.version_number}` : `Version ${version.version_number}`}
                </h3>
                <p className="text-sm text-gray-600">
                  {formatDistanceToNow(new Date(version.created_at), {
                    addSuffix: true,
                    locale: locale === 'ar' ? ar : enUS
                  })}
                </p>
                <p className="text-sm mt-1">{version.change_summary}</p>
              </div>
              <MetricChangeBadges metrics={version.metrics_summary} />
            </div>
          </TimelineItem>
        ))}
      </Timeline>
    </div>
  );
}

// components/VersionComparison.tsx
export function VersionComparison({ v1Id, v2Id }: { v1Id: number; v2Id: number }) {
  const [comparison, setComparison] = useState<ComparisonData>();
  const [activeSection, setActiveSection] = useState('metrics');

  useEffect(() => {
    fetchComparison(v1Id, v2Id).then(setComparison);
  }, [v1Id, v2Id]);

  return (
    <div className="grid grid-cols-2 gap-6">
      <div className="space-y-4">
        <h3>Version {comparison?.v1.version_number}</h3>
        <MetricsTable 
          metrics={comparison?.v1.metrics} 
          highlights={comparison?.changes.decreased}
          highlightColor="red"
        />
      </div>

      <div className="space-y-4">
        <h3>Version {comparison?.v2.version_number}</h3>
        <MetricsTable 
          metrics={comparison?.v2.metrics}
          highlights={comparison?.changes.increased} 
          highlightColor="green"
        />
      </div>

      <div className="col-span-2">
        <ChangeSummaryPanel changes={comparison?.changes} />
      </div>
    </div>
  );
}

// components/ChangeSummaryPanel.tsx
export function ChangeSummaryPanel({ changes }: { changes: ChangeData }) {
  const { locale } = useLocale();

  return (
    <div className="bg-gray-50 rounded-lg p-6">
      <h3 className="text-lg font-semibold mb-4">
        {locale === 'ar' ? 'ملخص التغييرات' : 'Change Summary'}
      </h3>

      <div className="grid grid-cols-3 gap-4">
        <ChangeCard
          title={locale === 'ar' ? 'تحسينات' : 'Improvements'}
          items={changes.improvements}
          icon={<TrendingUpIcon className="text-green-500" />}
        />
        <ChangeCard
          title={locale === 'ar' ? 'تراجعات' : 'Deteriorations'}
          items={changes.deteriorations}
          icon={<TrendingDownIcon className="text-red-500" />}
        />
        <ChangeCard
          title={locale === 'ar' ? 'تغييرات رئيسية' : 'Key Changes'}
          items={changes.key_changes}
          icon={<AlertCircleIcon className="text-blue-500" />}
        />
      </div>
    </div>
  );
}
